diff --git a/crates/mu-solo/src/app.rs b/crates/mu-solo/src/app.rs
--- a/crates/mu-solo/src/app.rs
+++ b/crates/mu-solo/src/app.rs
@@ -1903,7 +1903,7 @@ impl App {
     fn handle_overlay_key(&mut self, vp: &mut DynamicViewport, key: KeyEvent) -> Result<bool> {
         let Some(mut overlay) = self.overlay.take() else {
             return Ok(false);
         };
@@ -1917,16 +1917,8 @@ impl App {
             (_, KeyCode::Char('c')) => {
                 let text = overlay
                     .lines
                     .iter()
                     .map(|l| {
                         l.spans
                             .iter()
                             .map(|s| s.content.as_ref())
                             .collect::<String>()
                     })
                     .collect::<Vec<_>>()
                     .join("\n");
-                // Don't `?` here: the overlay was taken out at the top of this
-                // fn and is only restored at the bottom — propagating would leak
-                // it (modal silently dies). Report the outcome via flash either
-                // way and fall through to the restore.
-                match copy_to_clipboard_or_file(text.trim(), self.clipboard_command.as_deref()) {
-                    Ok(outcome) => {
-                        self.set_flash(format!("\u{2713} copied {} \u{b7} {outcome}", overlay.title))
-                    }
-                    Err(e) => self.set_flash(format!("copy failed: {e}")),
-                }
+                let outcome =
+                    copy_to_clipboard_or_file(text.trim(), self.clipboard_command.as_deref())?;
+                self.set_flash(format!("\u{2713} copied {} \u{b7} {outcome}", overlay.title));
             }
             (_, KeyCode::Up) | (KeyModifiers::ALT, KeyCode::Char('k')) => {
                 overlay.scroll = overlay.scroll.saturating_sub(1);
             }
@@ -1957,6 +1949,6 @@ impl App {
             (_, KeyCode::Home) => overlay.scroll = 0,
             (_, KeyCode::End) => overlay.scroll = usize::MAX,
             _ => {}
         }
         self.overlay = Some(overlay);
         Ok(false)
     }

diff --git a/src/editor.rs b/src/editor.rs
--- a/src/editor.rs
+++ b/src/editor.rs
@@ -10,17 +10,16 @@ impl Editor {
     /// Handle a key while a modal is open. The modal is moved out of `self`
     /// at the top and put back at the bottom so we can mutate it freely.
     fn handle_modal_key(&mut self, key: Key) -> Result<()> {
         let Some(mut modal) = self.modal.take() else {
             return Ok(());
         };
         match key {
             Key::Up => modal.scroll = modal.scroll.saturating_sub(1),
             Key::Down => modal.scroll = modal.scroll.saturating_add(1),
             // Copy the modal's text to the clipboard, then keep it open.
-            Key::Copy => match copy_to_clipboard(&modal.text) {
-                Ok(()) => self.flash = Some("copied".into()),
-                Err(e) => self.flash = Some(format!("copy failed: {e}")),
-            },
+            Key::Copy => copy_to_clipboard(&modal.text)?,
             _ => {}
         }
         // Restore the modal so it stays on screen.
         self.modal = Some(modal);
         Ok(())
     }
